async (page) => {
  let logs = 5;
  const treeCoords = [
    {x:205, y:131}, {x:215, y:126}, {x:198, y:123}, 
    {x:213, y:133}, {x:196, y:130}, {x:186, y:158},
    {x:186, y:165}, {x:175, y:164}
  ];

  for (const coord of treeCoords) {
    if (logs >= 10) break;

    // Find the entity label for this oak in current map
    const label = await page.evaluate((c) => {
      const m = window.__latestAsciiMap;
      if (!m || m.error) return null;
      // Parse legend to find entity at this position
      const lines = m.legendText.split('\n');
      for (const line of lines) {
        if (line.includes(`(${c.x},${c.y})`)) {
          const match = line.match(/E(\d+)/);
          if (match) return match[0];
        }
      }
      return null;
    }, coord);

    if (label) {
      const r = await page.evaluate((lbl) => JSON.stringify(window.__clickEntity(lbl)), label);
      const parsed = JSON.parse(r);
      await page.waitForTimeout(4000);

      logs = await page.evaluate(() => {
        const s = window.__latestGameState;
        return s.inventory ? s.inventory.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0) : 0;
      });
    } else {
      // Try clicking the tile directly (walk there)
      await page.evaluate(({x, y}) => window.__clickTile(x, y), coord);
      await page.waitForTimeout(3000);
      // Now try clicking entity 0 or 1 (closest)
      const r = await page.evaluate(() => {
        const m = window.__latestAsciiMap;
        if (!m) return null;
        // Find Oak in legend close to player
        const lines = m.legendText.split('\n');
        for (const line of lines) {
          if (line.includes('[^]') && line.includes('Oak')) {
            const match = line.match(/(E\d+)/);
            if (match) return match[0];
          }
        }
        return null;
      });
      if (r) {
        await page.evaluate((lbl) => window.__clickEntity(lbl), r);
        await page.waitForTimeout(4000);
        logs = await page.evaluate(() => {
          const s = window.__latestGameState;
          return s.inventory ? s.inventory.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0) : 0;
        });
      }
    }
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({ pos: s.player_position, logs: s.inventory ? s.inventory.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0) : 0, hp: s.player_stats.hp, max_hp: s.player_stats.max_hp });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return finalState;
}

