async (page) => {
  let logs = 7;

  // Repeat: extract oaks from current view and chop them
  for (let round = 0; round < 3 && logs < 10; round++) {
    const oakCoords = await page.evaluate(() => {
      const m = window.__latestAsciiMap;
      if (!m) return [];
      const lines = m.legendText.split('\n');
      const coords = [];
      for (const line of lines) {
        if (line.includes('Oak') && line.includes('at (')) {
          const match = line.match(/at \((\d+),(\d+)\)/);
          if (match) coords.push({x: parseInt(match[1]), y: parseInt(match[2])});
        }
      }
      return coords.slice(0, 5);
    });

    for (const coord of oakCoords) {
      if (logs >= 10) break;
      await page.evaluate(({x, y}) => window.__clickTile(x, y), coord);
      await page.waitForTimeout(7000);
      logs = await page.evaluate(() => {
        const s = window.__latestGameState;
        return s.inventory ? s.inventory.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0) : 0;
      });
    }

    if (logs < 10) {
      // Wait for tree respawn
      await page.waitForTimeout(15000);
    }
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({ 
      pos: s.player_position, 
      logs: s.inventory ? s.inventory.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0) : 0, 
      hp: s.player_stats.hp, max_hp: s.player_stats.max_hp, 
      level: s.player_stats.level,
      quest_stage: s.quests ? (s.quests.find(q=>q.key==='foresting') || {}).stage : null
    });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return finalState;
}

